// Build lead_id → dify_dataset_id lookup
const items = $input.all();
const map = {};
for (const item of items) {
  const { lead_id, dify_dataset_id } = item.json;
  if (lead_id && dify_dataset_id) {
    map[String(lead_id)] = dify_dataset_id;
  }
}
// Store in static data for later nodes
const staticData = $getWorkflowStaticData('global');
staticData.datasetMap = map;
return [{ json: { datasetMap: map, clientCount: Object.keys(map).length } }];

// Group calls by lead_id, attach dataset_id
const items = $input.all();
const datasetMap = $('Build Dataset Map').first().json.datasetMap || {};

if (items.length === 0 || !items[0].json.id) {
  return [{ json: { _skip: true, type: 'calls', message: 'No calls today' } }];
}

const grouped = {};
for (const item of items) {
  const { id, filename, lead_id, transcript_text } = item.json;
  if (!id || !lead_id) continue;
  const lid = String(lead_id);
  if (!grouped[lid]) grouped[lid] = { lead_id: lid, calls: [], dataset_id: datasetMap[lid] || null };
  grouped[lid].calls.push({ id, filename, text: (transcript_text || '').slice(0, 30000) });
}

return Object.values(grouped).map(g => ({ json: g }));

// Group chat messages by lead_id, attach dataset_id
const items = $input.all();
const datasetMap = $('Build Dataset Map').first().json.datasetMap || {};

if (items.length === 0 || !items[0].json.lead_id) {
  return [{ json: { _skip: true, type: 'chats', message: 'No chats today' } }];
}

const grouped = {};
for (const item of items) {
  const { lead_id, chat_title, sender, message_text, message_date } = item.json;
  if (!lead_id) continue;
  const lid = String(lead_id);
  if (!grouped[lid]) grouped[lid] = { lead_id: lid, chat_title: chat_title || '', messages: [], dataset_id: datasetMap[lid] || null };
  grouped[lid].messages.push(`[${message_date}] ${sender}: ${message_text}`);
}

return Object.values(grouped).map(g => ({
  json: {
    lead_id: g.lead_id,
    chat_title: g.chat_title,
    dataset_id: g.dataset_id,
    content: g.messages.slice(0, 200).join('\n'),
    message_count: g.messages.length
  }
}));

// Build GLM-4 request for call summary
const { lead_id, calls, dataset_id } = $json;
const combined = calls.map((c, i) => `--- Звонок ${i+1} (${c.filename}) ---\n${c.text}`).join('\n\n');
const callIds = calls.map(c => c.id);

return [{ json: {
  lead_id,
  dataset_id,
  call_ids: callIds,
  content: combined,
  source_type: 'call',
  prompt: 'Ты бизнес-аналитик. Проанализируй транскрипцию(и) созвона с клиентом.\nВыдай:\n1) Краткое резюме (2-3 предл.)\n2) Участники звонка\n3) Ключевые договорённости\n4) Action Items с дедлайнами (если есть)\n5) Риски/проблемы\n6) Тон клиента (позитивный/нейтральный/негативный)\nФормат: Markdown. Не более 1500 слов.'
} }];

// Build GLM-4 request for chat summary
const { lead_id, chat_title, dataset_id, content, message_count } = $json;

return [{ json: {
  lead_id,
  dataset_id,
  content,
  source_type: 'chat',
  chat_title,
  message_count,
  prompt: 'Ты куратор клиентского отдела. Проанализируй переписку с клиентом в Telegram за сегодня.\nВыдай:\n1) Краткое резюме (2-3 предл.)\n2) Ключевые вопросы клиента\n3) Решённые вопросы ✅\n4) Нерешённые вопросы ❓\n5) Action Items (если есть)\n6) Общий тон клиента\nФормат: Markdown.'
} }];

// Extract summary from GLM response for calls
const glmResp = $json;
const prev = $('Prepare Call GLM Request').first().json;
const msg = glmResp.choices?.[0]?.message || {};
const summary = (msg.content || msg.reasoning_content || 'Ошибка генерации').trim();
const dateStr = new Date().toISOString().slice(0, 10);
const callsInfo = prev.call_ids?.length > 1 ? `${prev.call_ids.length} звонка` : '1 звонок';

return [{ json: {
  lead_id: prev.lead_id,
  dataset_id: prev.dataset_id,
  call_ids: prev.call_ids,
  source_type: 'call',
  summary,
  filename: `LEAD-${prev.lead_id}_call_${dateStr}.md`,
  doc_name: `[${dateStr}] LEAD-${prev.lead_id} — Созвоны (${callsInfo})`,
  date: dateStr
} }];

// Extract summary from GLM response for chats
const glmResp = $json;
const prev = $('Prepare Chat GLM Request').first().json;
const msg = glmResp.choices?.[0]?.message || {};
const summary = (msg.content || msg.reasoning_content || 'Ошибка генерации').trim();
const dateStr = new Date().toISOString().slice(0, 10);

return [{ json: {
  lead_id: prev.lead_id,
  dataset_id: prev.dataset_id,
  source_type: 'chat',
  chat_title: prev.chat_title,
  message_count: prev.message_count,
  summary,
  filename: `LEAD-${prev.lead_id}_chat_${dateStr}.md`,
  doc_name: `[${dateStr}] LEAD-${prev.lead_id} — Telegram-чат (${prev.message_count} сообщ.)`,
  date: dateStr
} }];

// Push to Dify: use per-client dataset_id if available, else fallback to env
const { dataset_id, doc_name, summary } = $json;
const effectiveDatasetId = dataset_id || $env.DIFY_DATASET_ID;
return [{ json: { ...$json, effective_dataset_id: effectiveDatasetId, ready: true } }];

const { dataset_id, doc_name, summary } = $json;
const effectiveDatasetId = dataset_id || $env.DIFY_DATASET_ID;
return [{ json: { ...$json, effective_dataset_id: effectiveDatasetId, ready: true } }];

// Save call summary to DB + mark dify_doc_id
const difyResp = $json;
const prev = $('Resolve Call Dataset').first().json;
const docId = difyResp.document?.id || difyResp.id || '';

return [{ json: {
  lead_id: prev.lead_id,
  source_type: 'call',
  call_ids: prev.call_ids,
  summary: prev.summary,
  date: prev.date,
  dify_doc_id: docId,
  filename: prev.filename
} }];

const difyResp = $json;
const prev = $('Resolve Chat Dataset').first().json;
const docId = difyResp.document?.id || difyResp.id || '';

return [{ json: {
  lead_id: prev.lead_id,
  source_type: 'chat',
  summary: prev.summary,
  date: prev.date,
  dify_doc_id: docId,
  filename: prev.filename
} }];
